3565   Use &U = I->getOperandUse(OpNo);
3566   Value *V = U.get();
3567   Type *VTy = V->getType();
3568 
3569   if (DemandedMask == fcNone) {
3570     if (isa<PoisonValue>(V))
3571       return false;
3572     replaceUse(U, PoisonValue::get(VTy));
3573     return true;
3574   }
3575 
3576   // Handle constant
3577   Instruction *VInst = dyn_cast<Instruction>(V);
3578   if (!VInst) {
3579     // Handle constants and arguments
3580     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3581     Known.knownNot(~DemandedMask);
3582 
3583     if (Known.KnownFPClasses == fcNone) {
3584       if (isa<PoisonValue>(V))
3585         return false;
3586       replaceUse(U, PoisonValue::get(VTy));
3587       return true;
3588     }
3589 
3590     // Do not try to replace values which are already constants (unless we are
3591     // folding to poison). Doing so could promote poison elements to non-poison
3592     // constants.
3593     if (isa<Constant>(V))
3594       return false;
3595 
3596     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3597     if (!FoldedToConst || FoldedToConst == V)
3598       return false;
3599 
3600     replaceUse(U, FoldedToConst);
3601     return true;
3602   }
3603 
3604   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3605     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3606     DemandedMask &= ~NoFPClass;
3607   }
3608 
3609   if (Depth == MaxAnalysisRecursionDepth) {
3610     Known.knownNot(~DemandedMask);
3611     return false;
3612   }
3613 
3614   Value *NewVal;
3615 
3616   if (VInst->hasOneUse()) {
3617     // If the instruction has one use, we can directly simplify it.
3618     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3619   } else {
3620     // If there are multiple uses of this instruction, then we can simplify
3621     // VInst to some other value, but not modify the instruction.
3622     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3623                                                 Depth);
3624   }
3625 
3626   if (!NewVal)
3627     return false;
3628   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3629     salvageDebugInfo(*OpInst);
3630 
3631   replaceUse(U, NewVal);
3632   return true;
3633 }
