283   default:
284     llvm::computeKnownBits(I, Known, Q, Depth);
285     break;
286   case Instruction::And: {
287     // If either the LHS or the RHS are Zero, the result is zero.
288     if (SimplifyDemandedBits(I, 1, DemandedMask, RHSKnown, Q, Depth + 1) ||
