1190   if (IsSigned)
1191     APInt::sdivrem(C1, C2, Quotient, Remainder);
1192   else
1193     APInt::udivrem(C1, C2, Quotient, Remainder);
1194 
1195   return Remainder.isMinValue();
1196 }
